// ESP32 Servo Traffic Light
// =========================
// Three-phase traffic light (red/yellow/green) with a servo
// barrier gate that opens on green and closes on red.
//
// Uses ESP32 LEDC channels for both LED control and servo PWM
// — no external Servo library needed!
//
// Circuit:
//   GPIO16 -> 220R -> Red LED    -> GND
//   GPIO17 -> 220R -> Yellow LED -> GND
//   GPIO18 -> 220R -> Green LED  -> GND
//   GPIO19 -> Servo PWM (50 Hz LEDC channel)

#include <Arduino.h>

// --- LED Pins ---
const int RED_PIN    = 16;
const int YELLOW_PIN = 17;
const int GREEN_PIN  = 18;

// --- Servo via LEDC ---
const int SERVO_PIN     = 19;
const int SERVO_CH      = 3;    // LEDC channel 3
const int SERVO_FREQ    = 50;   // 50 Hz for servo
const int SERVO_RES     = 16;   // 16-bit resolution

// Servo pulse widths (in 16-bit duty for 50 Hz)
// 50 Hz period = 20 ms; 16-bit max = 65535
// 1 ms pulse (0 deg)  = 65535 * 1/20  = ~3277
// 2 ms pulse (180 deg) = 65535 * 2/20 = ~6554
const int SERVO_MIN = 3277;   // ~0 degrees
const int SERVO_MAX = 6554;   // ~180 degrees

// Timing (ms)
const unsigned long RED_TIME    = 5000;
const unsigned long YELLOW_TIME = 2000;
const unsigned long GREEN_TIME  = 5000;

void setServoAngle(int angle) {
  int duty = map(angle, 0, 180, SERVO_MIN, SERVO_MAX);
  ledcWrite(SERVO_CH, duty);
}

void allLedsOff() {
  digitalWrite(RED_PIN, LOW);
  digitalWrite(YELLOW_PIN, LOW);
  digitalWrite(GREEN_PIN, LOW);
}

void setup() {
  Serial.begin(115200);
  delay(200);

  Serial.println("==============================");
  Serial.println("  ESP32 Servo Traffic Light");
  Serial.println("==============================");
  Serial.println();

  // LED pins as outputs
  pinMode(RED_PIN, OUTPUT);
  pinMode(YELLOW_PIN, OUTPUT);
  pinMode(GREEN_PIN, OUTPUT);
  allLedsOff();

  // Configure servo LEDC channel
  ledcSetup(SERVO_CH, SERVO_FREQ, SERVO_RES);
  ledcAttachPin(SERVO_PIN, SERVO_CH);
  setServoAngle(0);  // Gate closed

  Serial.println("Traffic light + servo gate ready.");
  Serial.println("---");
}

void loop() {
  // RED phase — gate closed
  Serial.println("[RED] STOP — gate closing");
  allLedsOff();
  digitalWrite(RED_PIN, HIGH);
  setServoAngle(0);
  delay(RED_TIME);

  // YELLOW phase — gate still closed
  Serial.println("[YELLOW] CAUTION — preparing to open");
  allLedsOff();
  digitalWrite(YELLOW_PIN, HIGH);
  delay(YELLOW_TIME);

  // GREEN phase — gate opens
  Serial.println("[GREEN] GO — gate opening!");
  allLedsOff();
  digitalWrite(GREEN_PIN, HIGH);
  setServoAngle(90);
  delay(GREEN_TIME);

  // Brief YELLOW before returning to RED
  Serial.println("[YELLOW] CAUTION — gate will close");
  allLedsOff();
  digitalWrite(YELLOW_PIN, HIGH);
  setServoAngle(45);  // Half-close
  delay(YELLOW_TIME);
}
